import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import './Dashboard.css';

export default function Dashboard() {
  const { auth, apiHeaders } = useAuth();
  const [individu, setIndividu] = useState(null);
  const [dias, setDias] = useState([]);
  const [latestBilan, setLatestBilan] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    if (!auth?.uuid) return;
    const fetchAll = async () => {
      setLoading(true);
      try {
        const [indRes, diasRes] = await Promise.all([
          axios.get(`/api/student/individu/${auth.uuid}`, { headers: apiHeaders }),
          axios.get(`/api/student/dias/${auth.uuid}`, { headers: apiHeaders }),
        ]);
        setIndividu(indRes.data);
        const sortedDias = diasRes.data?.sort((a, b) => b.anneeAcademiqueId - a.anneeAcademiqueId) || [];
        setDias(sortedDias);

        if (sortedDias.length > 0) {
          try {
            const bRes = await axios.get(
              `/api/student/bilans/${auth.uuid}/${sortedDias[0].id}`,
              { headers: apiHeaders }
            );
            if (bRes.data?.length > 0) {
              const sorted = [...bRes.data].sort((a, b) => b.id - a.id);
              setLatestBilan(sorted[0]);
            }
          } catch { /* bilans might not exist yet */ }
        }
      } catch (e) {
        setError('Impossible de charger les données. Veuillez réessayer.');
      } finally {
        setLoading(false);
      }
    };
    fetchAll();
  }, [auth, apiHeaders]);

  if (loading) return <div className="page-loader"><div className="spinner" /></div>;

  const latest = dias[0];
  const gradeColor = (m) => m >= 10 ? 'grade-pass' : m >= 8 ? 'grade-mid' : 'grade-fail';

  return (
    <div className="dashboard">
      <div className="page-header">
        <div>
          <h1>Bonjour, {individu?.prenomLatin || auth?.username} 👋</h1>
          <p className="page-subtitle">Bienvenue sur votre espace étudiant PROGRES</p>
        </div>
      </div>

      {error && <div className="error-banner">{error}</div>}

      {/* Student info banner */}
      {individu && (
        <div className="info-banner card">
          <div className="info-banner-avatar">
            {(individu.prenomLatin?.[0] || 'E').toUpperCase()}
          </div>
          <div className="info-banner-body">
            <h2>{individu.prenomLatin} {individu.nomLatin}</h2>
            <p className="arabic-name">{individu.prenomArabe} {individu.nomArabe}</p>
            <div className="info-chips">
              {latest && <>
                <span className="chip chip-blue">{latest.niveauLibelleLongLt}</span>
                <span className="chip chip-green">{latest.ofLlFiliere}</span>
                <span className="chip chip-gray">{latest.anneeAcademiqueCode}</span>
              </>}
            </div>
          </div>
        </div>
      )}

      {/* Stats cards */}
      <div className="stats-grid">
        <div className="stat-card">
          <div className="stat-icon stat-icon-blue">📚</div>
          <div className="stat-body">
            <p className="stat-label">Inscriptions</p>
            <p className="stat-value">{dias.length}</p>
            <p className="stat-sub">années académiques</p>
          </div>
        </div>

        <div className="stat-card">
          <div className="stat-icon stat-icon-green">🏆</div>
          <div className="stat-body">
            <p className="stat-label">Dernière moyenne</p>
            <p className={`stat-value ${latestBilan ? gradeColor(latestBilan.moyenne) : ''}`}>
              {latestBilan ? latestBilan.moyenne?.toFixed(2) : '—'}
            </p>
            <p className="stat-sub">{latestBilan?.periodeLibelleFr || 'Non disponible'}</p>
          </div>
        </div>

        <div className="stat-card">
          <div className="stat-icon stat-icon-purple">🎯</div>
          <div className="stat-body">
            <p className="stat-label">Crédits acquis</p>
            <p className="stat-value">{latestBilan?.creditAcquis ?? '—'}</p>
            <p className="stat-sub">{latestBilan ? `sur ${latestBilan.bilanUes?.reduce((s, u) => s + u.credit, 0) || '?'}` : 'Non disponible'}</p>
          </div>
        </div>

        <div className="stat-card">
          <div className="stat-icon stat-icon-orange">🎓</div>
          <div className="stat-body">
            <p className="stat-label">Cycle</p>
            <p className="stat-value" style={{ fontSize: '1rem' }}>
              {latest?.refLibelleCycle?.charAt(0).toUpperCase() + latest?.refLibelleCycle?.slice(1) || '—'}
            </p>
            <p className="stat-sub">{latest?.ofLlSpecialite || latest?.ofLlFiliere || ''}</p>
          </div>
        </div>
      </div>

      {/* Quick access */}
      <h2 className="section-title">Accès rapide</h2>
      <div className="quick-grid">
        {[
          { to: '/profile', icon: '👤', title: 'Mon Profil', desc: 'Informations personnelles' },
          { to: '/inscriptions', icon: '📋', title: 'Inscriptions', desc: 'Dossiers académiques' },
          { to: '/bilans', icon: '📊', title: 'Relevé de notes', desc: 'Bilans par semestre' },
          { to: '/groups', icon: '👥', title: 'Mes Groupes', desc: 'Groupes pédagogiques' },
        ].map(item => (
          <Link key={item.to} to={item.to} className="quick-card">
            <span className="quick-icon">{item.icon}</span>
            <div>
              <p className="quick-title">{item.title}</p>
              <p className="quick-desc">{item.desc}</p>
            </div>
            <span className="quick-arrow">›</span>
          </Link>
        ))}
      </div>

      {/* Latest inscription */}
      {latest && (
        <>
          <h2 className="section-title">Année en cours</h2>
          <div className="card inscription-card">
            <div className="ins-row">
              <span className="ins-label">Année académique</span>
              <span className="ins-value">{latest.anneeAcademiqueCode}</span>
            </div>
            <div className="ins-row">
              <span className="ins-label">Établissement</span>
              <span className="ins-value">{latest.llEtablissementLatin}</span>
            </div>
            <div className="ins-row">
              <span className="ins-label">Domaine</span>
              <span className="ins-value">{latest.ofLlDomaine}</span>
            </div>
            <div className="ins-row">
              <span className="ins-label">Filière</span>
              <span className="ins-value">{latest.ofLlFiliere}</span>
            </div>
            {latest.ofLlSpecialite && (
              <div className="ins-row">
                <span className="ins-label">Spécialité</span>
                <span className="ins-value">{latest.ofLlSpecialite}</span>
              </div>
            )}
            <div className="ins-row">
              <span className="ins-label">N° Inscription</span>
              <span className="ins-value mono">{latest.numeroInscription}</span>
            </div>
          </div>
        </>
      )}
    </div>
  );
}
